CREATE TABLE IF NOT EXISTS sup_supplier_admission (
 admission_id bigint NOT NULL,admission_no varchar(64) NOT NULL,candidate_supplier_code varchar(64) NOT NULL,candidate_supplier_name varchar(256) NOT NULL,tax_no varchar(64) NOT NULL,supplier_type varchar(32) NOT NULL,admission_status smallint NOT NULL COMMENT '1潜在 2待审核 3已通过 4已驳回 5已撤回',contact_name varchar(128) NOT NULL,contact_mobile varchar(32) NOT NULL,settlement_json json NOT NULL,reject_reason varchar(512) NULL,created_by bigint NOT NULL,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_by bigint NULL,updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),version int NOT NULL DEFAULT 0,deleted tinyint NOT NULL DEFAULT 0,PRIMARY KEY(admission_id),UNIQUE KEY uk_sup_admission_no(admission_no),UNIQUE KEY uk_sup_admission_tax(tax_no),KEY idx_sup_admission_status(admission_status,updated_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='供应商准入协同单';
